        method = http_request.method or 'GET'

        # Normalize path to prevent path traversal
        # Strip query string for path matching
        clean_path = path.split('?')[0].split('#')[0]
        # Normalize double slashes, etc.
        while '//' in clean_path:
            clean_path = clean_path.replace('//', '/')

        logger.info(f"Auth check: method={method}, path={clean_path}")

        # Strip any restricted headers that clients should not be able to set
        # These will be removed from the request before forwarding upstream
        headers_to_remove = []
        for header_name in headers:
            if header_name.lower() in RESTRICTED_HEADERS:
                headers_to_remove.append(header_name)
